// Pega os itens de entrada
const items = $input.all();

// Para cada item, transforma o campo "output" (string JSON) em objeto
return items.map(item => {
  const raw = item.json.output; // conteúdo em string
  let parsed = {};

  try {
    parsed = JSON.parse(raw); // converte para objeto
  } catch (error) {
    parsed = { error: "Falha ao converter JSON", detalhe: error.message };
  }

  return {
    json: parsed
  };
});

